import React, { useState, useEffect } from 'react';

const MapExplorer = () => {
  const [points, setPoints] = useState([]);

  useEffect(() => {
    const fetchCoordinates = async () => {
      try {
        const res = await fetch('http://localhost:5000/api/analytics/heatmap');
        const json = await res.json();
        if (json.success) setPoints(json.data);
      } catch (err) {
        console.error(err);
      }
    };
    fetchCoordinates();
  }, []);

  return (
    <div className="p-6 max-w-7xl mx-auto space-y-4">
      <div>
        <h1 className="text-3xl font-black text-slate-900 tracking-tight">GIS Map Explorer</h1>
        <p className="text-slate-500 text-sm">Geographic cluster view of all active issues. Connect Leaflet or Google Maps here.</p>
      </div>
      <div className="w-full h-[550px] bg-slate-100 rounded-2xl border-2 border-dashed border-slate-300 flex flex-col items-center justify-center p-6 text-center">
        <div className="bg-white p-5 border rounded-xl max-w-lg shadow-sm w-full">
          <div className="font-extrabold text-base text-slate-900 mb-1">🗺️ Map Viewport — Leaflet / Google Maps</div>
          <p className="text-xs text-slate-400 mb-4">
            Install <code className="bg-slate-100 px-1 rounded">react-leaflet</code> and replace this container with a <code className="bg-slate-100 px-1 rounded">MapContainer</code> component. Coordinates below are ready to use.
          </p>
          <div className="text-left font-mono text-[11px] bg-slate-50 p-3 rounded-lg border max-h-60 overflow-y-auto space-y-1">
            {points.length === 0 && <div className="text-slate-400 text-center py-2">No issues found in database.</div>}
            {points.map((pt, idx) => (
              <div key={idx} className="text-slate-600">
                📍 [{pt.latitude?.toFixed(4)}, {pt.longitude?.toFixed(4)}] &bull; {pt.category} &bull; <span className={pt.severity === 'Critical' ? 'text-red-600' : pt.severity === 'High' ? 'text-orange-600' : 'text-slate-500'}>{pt.severity}</span>
              </div>
            ))}
          </div>
          <div className="mt-3 text-xs text-slate-400">{points.length} active issues loaded</div>
        </div>
      </div>
    </div>
  );
};

export default MapExplorer;
